// ===== SECTION: SAFE STORAGE HELPERS =====
// localStorageやJSONが壊れても、ゲーム本体の起動を止めないための共通処理。
function safeStorageGet(key, fallback = null) {
    try {
        const value = localStorage.getItem(key);
        return value === null ? fallback : value;
    } catch (error) {
        console.warn(`[storage] Failed to read ${key}:`, error);
        return fallback;
    }
}

function safeStorageSet(key, value) {
    try {
        localStorage.setItem(key, value);
        return true;
    } catch (error) {
        console.warn(`[storage] Failed to write ${key}:`, error);
        return false;
    }
}

function safeStorageRemove(key) {
    try {
        localStorage.removeItem(key);
        return true;
    } catch (error) {
        console.warn(`[storage] Failed to remove ${key}:`, error);
        return false;
    }
}

function safeJSONParse(raw, fallback = null, label = 'JSON') {
    if (!raw) return fallback;
    try {
        return JSON.parse(raw);
    } catch (error) {
        console.warn(`[storage] Broken ${label}; ignoring saved data.`, error);
        return fallback;
    }
}

function safeStorageGetJSON(key, fallback = null) {
    return safeJSONParse(safeStorageGet(key, null), fallback, key);
}

function safeStorageSetJSON(key, data) {
    try {
        return safeStorageSet(key, JSON.stringify(data));
    } catch (error) {
        console.warn(`[storage] Failed to serialize ${key}:`, error);
        return false;
    }
}

function safeStorageGetInt(key, fallback, min = -Infinity, max = Infinity) {
    const raw = safeStorageGet(key, String(fallback));
    const parsed = parseInt(raw, 10);
    const value = Number.isFinite(parsed) ? parsed : fallback;
    return Math.min(max, Math.max(min, value));
}

