// HP formula takes floor level f; exp values are flat.
// Fixed-floor spawns (boss/event stages) use hardcoded values instead.
const ENEMY_DEFS = {
    hp:  (f, t) => ({
        NORMAL: 3+f,      ORC: 40+f*5,   BREAKER: 50+f*4,
        BOMBER: 8+f,      TURRET: 100+f*5, BOAR: 15+f*2,
        HEALER: 20+f*2,   AMBULATOR: 50+f*5, YONDER: 6+f*2,
        ROULETTE: 20+f*5, LAYER: 20+f*2, CLUSTER: 15+f*2,
        PHANTOM: 25+f*3,  SHADOW: 10+f*2, NESTER: 8+f*2,
        SPLITTER: 20+f*3, BLAZE: 15+f*2,  FROST: 15+f*2,
        SLIDER: 15+f*2,   CRAZY_G: f,
    })[t] ?? 3+f,
    exp: (t) => ({
        NORMAL: 5,   ORC: 40,     BREAKER: 45, BOMBER: 12,  TURRET: 40,
        BOAR: 25,    HEALER: 30,  AMBULATOR: 18, YONDER: 12, ROULETTE: 20,
        LAYER: 25,   CLUSTER: 12, PHANTOM: 30, SHADOW: 15,  NESTER: 10,
        SPLITTER: 20, BLAZE: 15,  FROST: 15,   SLIDER: 15,
    })[t] ?? 5,
};
