// スクリーンタイプ文字列から表示名を取得するヘルパー
function getScreenTypeDisplay(typeStr) {
    if (!typeStr) return null;
    const fromTestTypes = ROOM_TEST_TYPES.find(t => t.id === typeStr);
    if (fromTestTypes) return { en: fromTestTypes.name, ja: fromTestTypes.nameJa };
    return SCREEN_TYPE_EXTRA[typeStr] || null;
}
