// ===== SECTION: UI UPDATES =====
// Refreshes all HUD elements: HP, stamina bar, floor, equipment icons, minimap, log.
function updateUI() {
    // LIFE_RING: HP上限50%増加（getPlayerMaxHp()で反映）
    // 爆弾のターン経過処理
    bombs.forEach(b => b.timer--);
    let hasDetonation = true;
    while (hasDetonation) {
        hasDetonation = false;
        const readyBombs = bombs.filter(b => b.timer <= 0);
        for (const bomb of readyBombs) {
            if (bombs.includes(bomb)) {
                detonateBomb(bomb);
                hasDetonation = true;
            }
        }
    }
    // 突風の間: windTimerのカウントのみ（実際のスライドはwindGustSlide()で行う）
    if (isWindFloor) {
        windTimer++;
        if (windTimer === 4) addLog("The wind is picking up...");
    }
    isPlayerVisible = true; // 確実に表示状態にする
    _hudHP = `${player.hp}/${getPlayerMaxHp()}`;
    _hudHPColor = player.isShielded ? '#4ade80' : player.isBreaker ? '#f59e0b' : '#ededed';
    _hudStamina = player.stamina;
    _hudStaminaInfinite = player.isInfiniteStamina;
    _hudLV = player.level;
    _hudBestFloor = maxReachedFloor;
    _hudHasKey = player.hasKey;
    _hudSwordCount = player.swordCount;
    _hudArmorCount = player.armorCount;
    _hudGold = player.gold;
    _hudRingNames = player.equippedRings
        .map(id => id ? (RINGS.find(r => r.id === id)?.name || '') : '')
        .filter(n => n);
    if (isInEscapeRoom) {
        _hudFloorPrefix = '';
        _hudFloor = 'LIMINAL SPACE';
    } else if (floorLevel === -1) {
        _hudFloorPrefix = '';
        _hudFloor = 'END CREDITS';
    } else if (floorLevel === 100) {
        _hudFloorPrefix = 'FLOOR ';
        _hudFloor = 'LAST FLOOR';
    } else if (floorLevel >= 101) {
        _hudFloorPrefix = '';
        _hudFloor = floorLevel === DEEP_ENDING_FLOOR ? 'TRUE BOTTOM' : `DEEP ${formatFloor(floorLevel)} [${currentScreen.x+1},${currentScreen.y+1}]`;
    } else {
        _hudFloorPrefix = 'FLOOR ';
        _hudFloor = `${floorLevel}/100`;
    }
    _updateMinimapData();
}

function _updateMinimapData() {
    if (isInEscapeRoom) {
        _hudMinimapData = { type: 'escape', total: 10, current: _escapeRoomPage };
        return;
    }
    if (floorLevel === 1 || !multiScreenMode || !visitedScreens) {
        _hudMinimapData = null; return;
    }
    if (isRoomTestMode && forcedLayoutType === 'NOVEL_CORRIDOR') {
        _hudMinimapData = {
            type: 'corridor',
            current: currentScreen.x, total: screenGridCols,
            winStart: Math.max(0, currentScreen.x - 9),
            winEnd: Math.min(screenGridCols - 1, currentScreen.x + 9),
            visited: visitedScreens
        };
        return;
    }
    _hudMinimapData = {
        type: 'grid',
        rows: screenGridRows, cols: screenGridCols,
        current: { x: currentScreen.x, y: currentScreen.y },
        active: screenGrid?.active, visited: visitedScreens
    };
}
function updateMinimap() { _updateMinimapData(); }

// ===== SECTION: MAP GENERATION =====
// Fixed floor blocks are inside initMap() as: if (floorLevel === N) { ... return; }
// See CLAUDE.md for a full list of fixed floors and how to add new ones.

// アイテム配置：小さい部屋を優先する（面積の逆数で重み付け）
function _pickSmallRoom(roomList) {
    if (!roomList || roomList.length === 0) return null;
    const weights = roomList.map(r => 1 / (r.w * r.h));
    const total = weights.reduce((a, b) => a + b, 0);
    let rnd = Math.random() * total;
    for (let i = 0; i < roomList.length; i++) {
        rnd -= weights[i];
        if (rnd <= 0) return roomList[i];
    }
    return roomList[roomList.length - 1];
}

// ガチャ防止：フロアごとに指輪タイプを確定させる。一度決まったIDはsaveGameで永続化される。
function _pickSeededRing(fl, pool) {
    if (ringFloorSeeds[fl] !== undefined) {
        const found = pool.find(r => r.id === ringFloorSeeds[fl]);
        if (found) return found;
        return pool[0]; // fallback（poolが空のはずはないが安全のため）
    }
    const picked = pool[Math.floor(Math.random() * pool.length)];
    ringFloorSeeds[fl] = picked.id;
    return picked;
}

function _initFloor20() {
    addKeyLog("EVENT: DARKNESS BELOW");
    addLog("Both chambers are shrouded in impenetrable darkness.");
    addKeyLog("Find the KEY hidden below — then return and escape!");

    multiScreenMode = true;
    screenGridSize = 2; screenGridCols = 1; screenGridRows = 2;

    screenGrid = {
        maps:            Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => null)),
        enemies:         Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => [])),
        wisps:           Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => [])),
        tempWalls:       Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => [])),
        wind:            Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => false)),
        xWallScreens:    Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => false)),
        scrollWallState: Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => null)),
        ambushRooms:     Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => [])),
        types:           Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => null)),
    };
    visitedScreens = [[true], [false]];

    // ---- 上の画面 [sy=0, sx=0]: 暗闇の部屋 + DOOR ----
    {
        const _f20Map = Array.from({ length: ROWS }, () => Array(COLS).fill(SYMBOLS.WALL));
        const _f20En  = [];
        for (let y = 1; y < ROWS - 1; y++)
            for (let x = 1; x < COLS - 1; x++)
                _f20Map[y][x] = SYMBOLS.FLOOR;
        // 下通路（→下の暗闇部屋）x=18-21, y=ROWS-1〜ROWS-3
        for (let px = 18; px <= 21; px++) {
            _f20Map[ROWS - 1][px] = SYMBOLS.FLOOR;
            _f20Map[ROWS - 2][px] = SYMBOLS.FLOOR;
            _f20Map[ROWS - 3][px] = SYMBOLS.FLOOR;
        }
        // 散在する柱（通路付近・左上スタート付近は除外）
        for (let y = 4; y < ROWS - 4; y += 3) {
            for (let x = 4; x < COLS - 3; x += 3) {
                if (Math.random() >= 0.35) continue;
                if (x >= 16 && x <= 23 && y >= ROWS - 7) continue;
                if (x <= 10 && y <= 6) continue;
                _f20Map[y][x] = SYMBOLS.WALL;
                const _d20 = [[0,1],[0,-1],[1,0],[-1,0]][Math.floor(Math.random()*4)];
                const _ex = x + _d20[0], _ey = y + _d20[1];
                if (_ex >= 1 && _ex < COLS-1 && _ey >= 1 && _ey < ROWS-1)
                    _f20Map[_ey][_ex] = SYMBOLS.WALL;
            }
        }
        // プレイヤースタート位置付近を確実に床に
        for (let dy = -1; dy <= 1; dy++)
            for (let dx = -1; dx <= 1; dx++)
                _f20Map[4+dy][8+dx] = SYMBOLS.FLOOR;
        // DOOR（左上エリア）
        _f20Map[4][4] = SYMBOLS.DOOR;
        // 敵配置ヘルパー
        const _f20PlaceTop = (type, hp, exp) => {
            for (let t = 0; t < 300; t++) {
                const ex = 3 + Math.floor(Math.random() * (COLS - 6));
                const ey = 4 + Math.floor(Math.random() * (ROWS - 8));
                if (_f20Map[ey][ex] !== SYMBOLS.FLOOR) continue;
                if (Math.abs(ex - 19) < 5 && ey > ROWS - 6) continue;
                if (ex <= 9 && ey <= 6) continue;
                _f20En.push({ type, x: ex, y: ey, hp, maxHp: hp,
                    flashUntil: 0, offsetX: 0, offsetY: 0, expValue: exp, stunTurns: 0 });
                return;
            }
        };
        for (let i = 0; i < 6; i++) _f20PlaceTop('NORMAL', 18 + floorLevel, 18);
        _f20PlaceTop('ORC', 60 + floorLevel * 2, 80);
        screenGrid.maps[0][0]    = _f20Map;
        screenGrid.enemies[0][0] = _f20En;
    }

    // ---- 下の画面 [sy=1, sx=0]: 暗闇の部屋（blank_template、迷路壁＋中心壁ブロック） ----
    {
        const _f20Dark = Array.from({ length: ROWS }, () => Array(COLS).fill(SYMBOLS.WALL));
        const _f20DE   = [];
        for (let y = 1; y < ROWS - 1; y++)
            for (let x = 1; x < COLS - 1; x++)
                _f20Dark[y][x] = SYMBOLS.FLOOR;
        // 中心壁ブロック（y=11〜13, x=11〜28）
        for (let cy = 11; cy <= 13; cy++)
            for (let cx = 11; cx <= 28; cx++)
                _f20Dark[cy][cx] = SYMBOLS.WALL;
        // 上通路（←上の部屋と接続）x=18-21, y=0,1,2
        for (let px = 18; px <= 21; px++) {
            _f20Dark[0][px] = SYMBOLS.FLOOR;
            _f20Dark[1][px] = SYMBOLS.FLOOR;
            _f20Dark[2][px] = SYMBOLS.FLOOR;
        }
        // ランダム迷路壁（pillar+extension方式）
        const _f20MzPass = (_x, _y) => (_x >= 17 && _x <= 22 && _y <= 4);
        for (let my = 3; my <= ROWS - 3; my += 2) {
            for (let mx = 3; mx <= COLS - 3; mx += 2) {
                if (Math.random() >= 0.40) continue;
                if (_f20Dark[my][mx] !== SYMBOLS.FLOOR) continue;
                if (_f20MzPass(mx, my)) continue;
                _f20Dark[my][mx] = SYMBOLS.WALL;
                const _md = [[0,1],[0,-1],[1,0],[-1,0]][Math.floor(Math.random()*4)];
                const _mex = mx + _md[0], _mey = my + _md[1];
                if (_mey >= 1 && _mey < ROWS-1 && _mex >= 1 && _mex < COLS-1
                    && _f20Dark[_mey][_mex] === SYMBOLS.FLOOR && !_f20MzPass(_mex, _mey))
                    _f20Dark[_mey][_mex] = SYMBOLS.WALL;
            }
        }
        // 通路入口付近を確実に床に（入室直後の移動確保）
        for (let px = 18; px <= 21; px++)
            for (let py = 0; py <= 4; py++)
                _f20Dark[py][px] = SYMBOLS.FLOOR;
        // KEY配置：下の壁際の真ん中（固定）
        // y=ROWS-2=23 はランダム迷路壁の生成範囲外（max y=21）なので確実にFLOOR
        _f20Dark[ROWS - 2][Math.floor(COLS / 2)] = SYMBOLS.KEY;
        // 敵（YONDER×3 + PHANTOM×2）
        const _f20Specs = [
            { type: 'YONDER',  hp: 25 + floorLevel, exp: 15 },
            { type: 'YONDER',  hp: 25 + floorLevel, exp: 15 },
            { type: 'YONDER',  hp: 25 + floorLevel, exp: 15 },
            { type: 'PHANTOM', hp: 20 + floorLevel, exp: 20 },
            { type: 'PHANTOM', hp: 20 + floorLevel, exp: 20 },
        ];
        for (const sp of _f20Specs) {
            for (let t = 0; t < 500; t++) {
                const ex = 3 + Math.floor(Math.random() * (COLS - 6));
                const ey = 5 + Math.floor(Math.random() * (ROWS - 10));
                if (_f20Dark[ey][ex] !== SYMBOLS.FLOOR) continue;
                if (Math.abs(ex - 19) < 4 && ey < 5) continue;
                if (_f20DE.some(e => e.x === ex && e.y === ey)) continue;
                _f20DE.push({ type: sp.type, x: ex, y: ey, hp: sp.hp, maxHp: sp.hp,
                    flashUntil: 0, offsetX: 0, offsetY: 0, expValue: sp.exp, stunTurns: 0 });
                break;
            }
        }
        screenGrid.maps[1][0]    = _f20Dark;
        screenGrid.enemies[1][0] = _f20DE;
        screenGrid.types[1][0]   = 'blank_template';
    }

    // 両方の部屋を暗闇に
    screenGrid.types[0][0] = 'blank_template';

    // プレイヤースタート（上の部屋）
    player.x = 8; player.y = 4;
    currentScreen = { x: 0, y: 0 };
    map       = screenGrid.maps[0][0];
    enemies   = screenGrid.enemies[0][0];
    wisps     = [];
    tempWalls = [];
}

function _initFloor36() {
    addKeyLog("EVENT: ROULETTE PATROL");
    addKeyLog("A patrol room lies below. Find the KEY and return to the door.");
    addLog("Stay out of the R patrol's gaze.");

    multiScreenMode = true;
    screenGridSize = 2; screenGridCols = 1; screenGridRows = 2;

    screenGrid = {
        maps:            Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => null)),
        enemies:         Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => [])),
        wisps:           Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => [])),
        tempWalls:       Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => [])),
        wind:            Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => false)),
        xWallScreens:    Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => false)),
        scrollWallState: Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => null)),
        ambushRooms:     Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => [])),
        types:           Array.from({ length: 2 }, () => Array.from({ length: 1 }, () => null)),
        rgAlerted:       {}
    };
    visitedScreens = [[true], [false]];

    // ---- 上の画面 [sy=0, sx=0]: entrance chamber + locked door ----
    {
        const _f36Top = Array.from({ length: ROWS }, () => Array(COLS).fill(SYMBOLS.WALL));
        const _f36TopEnemies = [];
        for (let y = 1; y < ROWS - 1; y++)
            for (let x = 1; x < COLS - 1; x++)
                _f36Top[y][x] = SYMBOLS.FLOOR;

        for (let px = 18; px <= 21; px++) {
            _f36Top[ROWS - 1][px] = SYMBOLS.FLOOR;
            _f36Top[ROWS - 2][px] = SYMBOLS.FLOOR;
            _f36Top[ROWS - 3][px] = SYMBOLS.FLOOR;
        }

        const _topKeepClear = (x, y) =>
            (x <= 10 && y <= 7) ||
            (x >= 16 && x <= 23 && y >= ROWS - 7);
        for (let y = 4; y < ROWS - 4; y += 4) {
            for (let x = 5; x < COLS - 4; x += 5) {
                if (_topKeepClear(x, y) || Math.random() < 0.25) continue;
                _f36Top[y][x] = SYMBOLS.WALL;
                if (x + 1 < COLS - 1 && !_topKeepClear(x + 1, y)) _f36Top[y][x + 1] = SYMBOLS.WALL;
            }
        }

        player.x = 8; player.y = 4;
        for (let dy = -1; dy <= 1; dy++)
            for (let dx = -1; dx <= 1; dx++)
                _f36Top[player.y + dy][player.x + dx] = SYMBOLS.FLOOR;

        for (let dy = -1; dy <= 1; dy++)
            for (let dx = -1; dx <= 1; dx++)
                _f36Top[4 + dy][4 + dx] = SYMBOLS.FLOOR;
        _f36Top[4][4] = SYMBOLS.DOOR;

        const _placeTopEnemy36 = (type, hp, exp) => {
            for (let t = 0; t < 300; t++) {
                const ex = 3 + Math.floor(Math.random() * (COLS - 6));
                const ey = 5 + Math.floor(Math.random() * (ROWS - 10));
                if (_f36Top[ey][ex] !== SYMBOLS.FLOOR) continue;
                if (Math.abs(ex - player.x) + Math.abs(ey - player.y) < 8) continue;
                if (Math.abs(ex - 19) < 5 && ey > ROWS - 7) continue;
                if (_f36TopEnemies.some(e => e.x === ex && e.y === ey)) continue;
                _f36TopEnemies.push({ type, x: ex, y: ey, hp, maxHp: hp,
                    flashUntil: 0, offsetX: 0, offsetY: 0, expValue: exp, stunTurns: 0 });
                break;
            }
        };
        for (let i = 0; i < 4; i++) _placeTopEnemy36('NORMAL', 18 + floorLevel, 18);
        _placeTopEnemy36('ORC', 50 + floorLevel * 2, 60);

        screenGrid.maps[0][0]    = _f36Top;
        screenGrid.enemies[0][0] = _f36TopEnemies;
        screenGrid.types[0][0]   = 'blank_template';
    }

    // ---- 下の画面 [sy=1, sx=0]: ROULETTE_GUARD patrol room + KEY ----
    {
        const _f36Patrol = Array.from({ length: ROWS }, () => Array(COLS).fill(SYMBOLS.WALL));
        const _f36PatrolEnemies = [];
        for (let y = 1; y < ROWS - 1; y++)
            for (let x = 1; x < COLS - 1; x++)
                _f36Patrol[y][x] = SYMBOLS.FLOOR;

        for (let px = 18; px <= 21; px++) {
            _f36Patrol[0][px] = SYMBOLS.FLOOR;
            _f36Patrol[1][px] = SYMBOLS.FLOOR;
            _f36Patrol[2][px] = SYMBOLS.FLOOR;
        }

        const _key36X = Math.floor(COLS / 2), _key36Y = ROWS - 2;
        const _keep36Clear = (x, y) =>
            (x >= 17 && x <= 22 && y <= 5) ||
            (x >= 18 && x <= 21 && (y <= 7 || y >= ROWS - 6)) ||
            (Math.abs(x - _key36X) <= 2 && Math.abs(y - _key36Y) <= 2);

        for (let y = 3; y < ROWS - 3; y += 2) {
            for (let x = 3; x < COLS - 3; x += 2) {
                if (_keep36Clear(x, y) || Math.random() < 0.18) continue;
                _f36Patrol[y][x] = SYMBOLS.WALL;
                const dirs = [[0,1],[0,-1],[1,0],[-1,0]];
                const d = dirs[Math.floor(Math.random() * dirs.length)];
                const nx = x + d[0], ny = y + d[1];
                if (nx >= 1 && nx < COLS - 1 && ny >= 1 && ny < ROWS - 1 && !_keep36Clear(nx, ny))
                    _f36Patrol[ny][nx] = SYMBOLS.WALL;
            }
        }

        // 中央の大きな壁で、入口からキーへ一直線に進めない構造にする。
        for (let y = 8; y <= 17; y++)
            for (let x = 14; x <= 25; x++)
                _f36Patrol[y][x] = SYMBOLS.WALL;
        for (let y = 11; y <= 14; y++)
            for (let x = 18; x <= 21; x++)
                _f36Patrol[y][x] = SYMBOLS.WALL;
        for (let y = 0; y <= _key36Y; y++)
            for (let x = 18; x <= 21; x++)
                if (y <= 7 || y >= ROWS - 6) _f36Patrol[y][x] = SYMBOLS.FLOOR;
        for (let x = 12; x <= 27; x++) {
            _f36Patrol[7][x] = SYMBOLS.FLOOR;
            _f36Patrol[18][x] = SYMBOLS.FLOOR;
        }
        for (let y = 7; y <= 18; y++) {
            _f36Patrol[y][12] = SYMBOLS.FLOOR;
            _f36Patrol[y][27] = SYMBOLS.FLOOR;
        }
        for (let dy = -1; dy <= 1; dy++) {
            for (let dx = -2; dx <= 2; dx++) {
                const cx = _key36X + dx, cy = _key36Y + dy;
                if (cx >= 1 && cx < COLS - 1 && cy >= 1 && cy < ROWS - 1) _f36Patrol[cy][cx] = SYMBOLS.FLOOR;
            }
        }
        _f36Patrol[_key36Y][_key36X] = SYMBOLS.KEY;

        const _r36Hp = 25 + floorLevel;
        const _r36Patrols = [
            { x: 9,  y: 7,  dir: 1 },
            { x: 30, y: 8,  dir: 3 },
            { x: 10, y: 17, dir: 1 },
            { x: 30, y: 18, dir: 3 },
        ];
        for (const p of _r36Patrols) {
            for (let dy = -1; dy <= 1; dy++)
                for (let dx = -1; dx <= 1; dx++) {
                    const cx = p.x + dx, cy = p.y + dy;
                    if (cx >= 1 && cx < COLS - 1 && cy >= 1 && cy < ROWS - 1) _f36Patrol[cy][cx] = SYMBOLS.FLOOR;
                }
            _f36PatrolEnemies.push({ type: 'ROULETTE', x: p.x, y: p.y,
                hp: _r36Hp, maxHp: _r36Hp,
                flashUntil: 0, offsetX: 0, offsetY: 0,
                expValue: 30, stunTurns: 0,
                _rPhase: 1, _faceDir: p.dir, _rgPatrol: true });
        }

        // 右上隅に透明なCOLLECTION敵ρを潜ませる
        const _rhoX = COLS - 2, _rhoY = 2;
        _f36Patrol[_rhoY][_rhoX] = SYMBOLS.FLOOR; // 壁が置かれていても強制クリア
        if (!greekKillCounts['GREEK_RHO']) {
            _f36PatrolEnemies.push({
                type: 'GREEK_RHO', x: _rhoX, y: _rhoY,
                hp: 500, maxHp: 500,
                flashUntil: 0, offsetX: 0, offsetY: 0,
                expValue: 15, stunTurns: 0,
                flee: true, // 初期から主人公を避けて逃げ回る
            });
        }

        screenGrid.maps[1][0]    = _f36Patrol;
        screenGrid.enemies[1][0] = _f36PatrolEnemies;
        screenGrid.types[1][0]   = 'ROULETTE_GUARD';
    }

    currentScreen = { x: 0, y: 0 };
    map       = screenGrid.maps[0][0];
    enemies   = screenGrid.enemies[0][0];
    wisps     = [];
    tempWalls = [];
}

