    // 単画面用タレット設置ヘルパー: 周囲1マスの壁を除去し最長射線方向を返す（グローバルmap使用）
    function prepareTurretSpotSingle(x, y) {
        for (let dy = -1; dy <= 1; dy++) {
            for (let dx = -1; dx <= 1; dx++) {
                if (dx === 0 && dy === 0) continue;
                const nx = x + dx, ny = y + dy;
                if (nx < 1 || nx >= COLS - 1 || ny < 1 || ny >= ROWS - 1) continue;
                if (map[ny][nx] === SYMBOLS.WALL) map[ny][nx] = SYMBOLS.FLOOR;
            }
        }
        const _dirs = [{dx:0,dy:-1},{dx:1,dy:0},{dx:0,dy:1},{dx:-1,dy:0}];
        let bestDir = 0, maxDist = -1;
        for (let d = 0; d < 4; d++) {
            const { dx, dy } = _dirs[d];
            let dist = 0, tx = x + dx, ty = y + dy;
            while (tx >= 0 && tx < COLS && ty >= 0 && ty < ROWS && map[ty]?.[tx] !== SYMBOLS.WALL) {
                dist++; tx += dx; ty += dy;
            }
            if (dist > maxDist) { maxDist = dist; bestDir = d; }
        }
        return bestDir;
    }

