    // 溶岩の床の生成
    // B8-24F: 30%で小パッチ1つ / B25-49F: 氷なし時80% / B50F+: 確定・大量
    const canSpawnLava = (floorLevel >= 8);
    const lavaChance = (floorLevel >= 50) ? 1.0 : (floorLevel >= 25) ? (isIceFloor ? 0 : 0.8) : 0.30;
    const numLavaSwamps = (floorLevel >= 25) ? Math.floor(Math.random() * 3) + 2 : 1;
    const lavaWalkLen  = (floorLevel >= 25) ? 60 : 25;

