                    for (let _lx = _lwRoom.x; _lx < _lwRoom.x + _lwRoom.w; _lx++)
                        if (map[_ly] && map[_ly][_lx] === SYMBOLS.FLOOR) _lwCands.push({ x: _lx, y: _ly });
                if (_lwCands.length === 0) continue;
