                        if (_ssx < 1 || _ssx >= COLS - 1 || _ssy < 1 || _ssy >= ROWS - 1) break;
                        if (!canEnemyMove(_ssx, _ssy, e)) break;
                        if (_ssx === player.x && _ssy === player.y) break;
