                        // LATIN_P / GREEK_RHO: avoid warp pads (would get teleported away)
                        if ((ent.type === 'LATIN_P' || ent.type === 'GREEK_RHO') && map[ny]?.[nx] === SYMBOLS.WARP_PAD) return false;
