function _triggerIceCrossMadman(brokenX, brokenY) {
    if (_iceCrossMadmanSpawned) return;
    if (!multiScreenMode || !screenGrid || !screenGrid.types) return;
    if (screenGrid.types[currentScreen.y][currentScreen.x] !== 'ICE_CROSS') return;
    _iceCrossMadmanSpawned = true;
    // 通路入口候補（プレイヤーから最も遠い順に試す）
    const _passages = [[1, 12], [COLS - 2, 12], [19, 1], [19, ROWS - 2]];
    _passages.sort((a, b) =>
        (Math.abs(b[0] - player.x) + Math.abs(b[1] - player.y)) -
        (Math.abs(a[0] - player.x) + Math.abs(a[1] - player.y))
    );
    for (const [spx, spy] of _passages) {
        if (map[spy][spx] === SYMBOLS.WALL) continue;
        if (enemies.some(e => e.hp > 0 && e.x === spx && e.y === spy)) continue;
        const madHp = Math.floor(floorLevel * 20);
        enemies.push({
            type: 'PAUPER_SHADE', x: spx, y: spy,
            hp: madHp, maxHp: madHp,
            flashUntil: 0, offsetX: 0, offsetY: 0,
            expValue: 50, stunTurns: 0
        });
        addKeyLog("!! A Wandering Shade emerges from the shadows!!");
        spawnFloatingText(spx, spy, "SHADE!!", '#ef4444');
        return;
    }
}

